{
var seed = GetInt(parameters, "seed", context.Seed);
    var density = GetFloat(parameters, "traceDensity", 0.5f);
    var traceWidth = GetInt(parameters, "traceWidth", 2);
    var roundness = GetFloat(parameters, "roundness", 0.5f);
    var boardColor = GetColor(parameters, "boardColor", System.Windows.Media.Color.FromRgb(30, 50, 20));
    var traceColor = GetColor(parameters, "traceColor", System.Windows.Media.Color.FromRgb(200, 180, 100));
    var padColor = GetColor(parameters, "padColor", System.Windows.Media.Color.FromRgb(180, 160, 80));
    var invert = GetBool(parameters, "invert", false);

    var size = context.TileSize;
    var buffer = new PixelBuffer(size, size);

    var bR = boardColor.R / 255f; var bG = boardColor.G / 255f; var bB = boardColor.B / 255f;
    var tR = traceColor.R / 255f; var tG = traceColor.G / 255f; var tB = traceColor.B / 255f;
    var pR = padColor.R / 255f; var pG = padColor.G / 255f; var pB = padColor.B / 255f;

    // Initialize with board color
    buffer.ParallelForEachPixel((x, y) =>
    {
        buffer.SetPixel(x, y, bR, bG, bB, 1f);
    });

    // Trace grid parameters
    var gridSize = Math.Max(8, size / 8);
    var cols = size / gridSize;
    var rows = size / gridSize;

    // Generate pads at grid intersections
    var padPresent = new bool[cols, rows];
    for (var gy = 0; gy < rows; gy++)
    {
        for (var gx = 0; gx < cols; gx++)
        {
            var roll = HashToUnit(gx, gy, seed);
            padPresent[gx, gy] = roll < density * 0.7f;
        }
    }

    // Draw pads
    for (var gy = 0; gy < rows; gy++)
    {
        for (var gx = 0; gx < cols; gx++)
        {
            if (!padPresent[gx, gy]) continue;

            var cx = gx * gridSize + gridSize / 2;
            var cy = gy * gridSize + gridSize / 2;
            var padRadius = traceWidth + 1;

            for (var dy = -padRadius; dy <= padRadius; dy++)
            {
                for (var dx = -padRadius; dx <= padRadius; dx++)
                {
                    var px = cx + dx;
                    var py = cy + dy;

                    var dist = MathF.Sqrt(dx * dx + dy * dy);
                    if (dist <= padRadius)
                    {
                        var (r, g, b, a) = buffer.GetPixelWrapped(px, py);
                        // Blend pad color
                        var blend = dist / padRadius;
                        buffer.SetPixelWrapped(px, py,
                            Lerp(pR, r, blend),
                            Lerp(pG, g, blend),
                            Lerp(pB, b, blend), 1f);
                    }
                }
            }
        }
    }

    // Generate traces (horizontal and vertical segments)
    var localSeed = seed + 100;
    for (var gy = 0; gy < rows; gy++)
    {
        for (var gx = 0; gx < cols; gx++)
        {
            if (!padPresent[gx, gy]) continue;

            // Try to connect to neighbor pads
            var dirs = new[] { (1, 0), (0, 1), (-1, 0), (0, -1) };
            // Shuffle directions based on hash
            var shuffle = HashToUnit(gx, gy, localSeed);
            var startIdx = (int)(shuffle * 4);
            for (var d = 0; d < 4; d++)
            {
                var (dx, dy) = dirs[(startIdx + d) % 4];
                var nx = gx + dx;
                var ny = gy + dy;
                if (nx < 0 || nx >= cols || ny < 0 || ny >= rows) continue;
                if (!padPresent[nx, ny]) continue;

                // Connect with trace line
                var x0 = gx * gridSize + gridSize / 2;
                var y0 = gy * gridSize + gridSize / 2;
                var x1 = nx * gridSize + gridSize / 2;
                var y1 = ny * gridSize + gridSize / 2;

                DrawTrace(buffer, x0, y0, x1, y1, traceWidth, tR, tG, tB, size);
            }
        }
    }

    // Add some random via points
    for (var i = 0; i < cols * rows * density * 0.1f; i++)
    {
        var vx = (int)(HashToUnit(i, seed * 3, 555) * size);
        var vy = (int)(HashToUnit(i * 7, seed * 5, 666) * size);
        var viaRadius = traceWidth;

        for (var dy = -viaRadius; dy <= viaRadius; dy++)
        {
            for (var dx = -viaRadius; dx <= viaRadius; dx++)
            {
                var px = vx + dx;
                var py = vy + dy;
                if (dx * dx + dy * dy <= viaRadius * viaRadius)
                {
                    buffer.SetPixelWrapped(px, py, tR * 0.8f, tG * 0.8f, tB * 0.8f, 1f);
                }
            }
        }

        // Center hole
        for (var dy = -1; dy <= 1; dy++)
        {
            for (var dx = -1; dx <= 1; dx++)
            {
                var px = vx + dx;
                var py = vy + dy;
                if (dx * dx + dy * dy <= 1)
                {
                    buffer.SetPixelWrapped(px, py, bR, bG, bB, 1f);
                }
            }
        }
    }

    return buffer;

private static void DrawTrace(PixelBuffer buffer, int x0, int y0, int x1, int y1, int width, float r, float g, float b, int size)
{
    // Simple orthogonal trace with optional corner rounding
    var midX = (x0 + x1) / 2;
    var midY = (y0 + y1) / 2;

    // Horizontal then vertical (L-shaped)
    DrawLine(buffer, x0, y0, midX, y0, width, r, g, b, size);
    DrawLine(buffer, midX, y0, midX, y1, width, r, g, b, size);
    DrawLine(buffer, midX, y1, x1, y1, width, r, g, b, size);
}

private static void DrawLine(PixelBuffer buffer, int x0, int y0, int x1, int y1, int width, float r, float g, float b, int size)
{
    var dx = MathF.Abs(x1 - x0);
    var dy = MathF.Abs(y1 - y0);
    var sx = x0 < x1 ? 1 : -1;
    var sy = y0 < y1 ? 1 : -1;
    var err = dx - dy;
    var cx = x0;
    var cy = y0;

    while (true)
    {
        // Draw filled circle at each point for width
        for (var wy = -width / 2; wy <= width / 2; wy++)
        {
            for (var wx = -width / 2; wx <= width / 2; wx++)
            {
                var px = cx + wx;
                var py = cy + wy;
                buffer.SetPixelWrapped(px, py, r, g, b, 1f);
            }
        }

        if (cx == x1 && cy == y1) break;
        var e2 = 2 * err;
        if (e2 > -dy) { err -= dy; cx += sx; }
        if (e2 < dx) { err += dx; cy += sy; }
    }
    }
}
